VALUES
  ('pukao-77f8735d-moex-00170', 'pukao-77f8735d', 'pukao-77f8735d-moex-110-85716566', 'sub-pukao-77f8735d-03', NULL, 'single_choice', '資本主義盛行的社會易出現貧富不均問題，政府應建立社會安全制度，以保障國人基本的經濟與 社會安全。根據衛生福利部公布的社會福利政策綱領，有關我國社會安全制度，下列敘述何者最 為正確？', '["以社會救助為主，社會保險為輔，社會津貼為最後一道防線", "以社會津貼為主，社會救助為輔，社會保險為最後一道防線", "以社會保險為主，社會津貼為輔，社會救助為最後一道防線", "以社會救助為主，社會津貼為輔，社會保險為最後一道防線"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:05+00:00", "source_pdf_sha1": "aae8d0e445d8", "answer_pdf_sha1": "fb40082def78", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "426", "s": "2802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生行政學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "衛生行政"}'::jsonb, NULL),
  ('pukao-77f8735d-moex-00171', 'pukao-77f8735d', 'pukao-77f8735d-moex-110-85716566', 'sub-pukao-77f8735d-03', NULL, 'single_choice', '有關急性後期照護（post-acutecare）和相關衛生行政措施，下列敘述何者錯誤？', '["急性後期照護是在急性疾病後復健積極的介入照護，讓病患恢復身體狀況，減少非必要的再入院", "日間照護為衛生福利部中央健康保險署急性後期整合照護計畫的急性後期照護模式之一", "慢性腎臟病已納入衛生福利部中央健康保險署急性後期整合照護計畫推動範圍", "衛生福利部中央健康保險署急性後期整合照護計畫規劃之衰弱高齡病患急性後期照護以2-3週 為原則，最多支付到4週"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:05+00:00", "source_pdf_sha1": "aae8d0e445d8", "answer_pdf_sha1": "fb40082def78", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "426", "s": "2802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生行政學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "衛生行政"}'::jsonb, NULL),
  ('pukao-77f8735d-moex-00172', 'pukao-77f8735d', 'pukao-77f8735d-moex-110-85716566', 'sub-pukao-77f8735d-03', NULL, 'single_choice', '為尊重病人醫療自主、保障其善終權益，政府制定病人自主權利法。有關此法，下列敘述何者正 確？', '["預立醫療決定書之適用對象限於被判定為末期病人者", "此法之主要立法目的，為避免末期病人承受過度醫療，例如心肺復甦術", "病人可選擇接受、拒絕或撤除維持生命治療、人工營養及流體餵養等醫療照護", "在病人疾病痛苦難以忍受、疾病無法治癒狀況下，醫師須確認病人自主同意，方可開立處方、 準備並提供藥物，協助病人提早結束生命"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:05+00:00", "source_pdf_sha1": "aae8d0e445d8", "answer_pdf_sha1": "fb40082def78", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "426", "s": "2802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生行政學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "衛生行政"}'::jsonb, NULL),
  ('pukao-77f8735d-moex-00173', 'pukao-77f8735d', 'pukao-77f8735d-moex-110-85716566', 'sub-pukao-77f8735d-03', NULL, 'single_choice', '醫療、基因、健康檢查之個人資料，不得蒐集、處理和利用，但有法律明文規定者不在此限。此 規定規範於以下那個法規？', '["人體生物資料庫管理條例", "醫療法", "醫師法、護理人員法等醫事人員法規", "個人資料保護法"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:05+00:00", "source_pdf_sha1": "aae8d0e445d8", "answer_pdf_sha1": "fb40082def78", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "426", "s": "2802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生行政學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "衛生行政"}'::jsonb, NULL),
  ('pukao-77f8735d-moex-00174', 'pukao-77f8735d', 'pukao-77f8735d-moex-110-85716566', 'sub-pukao-77f8735d-03', NULL, 'single_choice', '因應少子女化趨勢，我國研擬107-113年我國少子女化對策計畫，下列那一項不是由衛生福利部 負責執行？', '["建構完善生養環境，包括孕產婦產前健康檢查、嬰幼兒健康照護", "0歲到2歲（未滿）育兒津貼發放與托育準公共服務規劃", "防治兒少虐待與疏忽，落實兒少保護", "2歲到6歲（未滿）幼兒的幼兒園學費補助"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:05+00:00", "source_pdf_sha1": "aae8d0e445d8", "answer_pdf_sha1": "fb40082def78", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "426", "s": "2802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生行政學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "衛生行政"}'::jsonb, NULL),
  ('pukao-77f8735d-moex-00175', 'pukao-77f8735d', 'pukao-77f8735d-moex-110-85716566', 'sub-pukao-77f8735d-03', NULL, 'single_choice', '臺灣地區衛生行政組織架構中，衛生福利部和各縣市衛生局的關係為：', '["直屬關係", "業務關係", "附屬單位", "沒有關係"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:05+00:00", "source_pdf_sha1": "aae8d0e445d8", "answer_pdf_sha1": "fb40082def78", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "426", "s": "2802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生行政學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "衛生行政"}'::jsonb, NULL),
  ('pukao-77f8735d-moex-00176', 'pukao-77f8735d', 'pukao-77f8735d-moex-110-85716566', 'sub-pukao-77f8735d-03', NULL, 'single_choice', '有關國家消除C型肝炎政策，下列敘述何者錯誤？', '["目標為2025年無C型肝炎新發個案", "加強洗腎透析患者為C型肝炎感染高風險族群篩檢率", "成人健檢項目擴大補助國人B、C型肝炎45-79歲（原住民40-79歲）終身一次篩檢", "針對C型肝炎傳染途徑進行阻斷，避免新感染與再感染的風險"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:05+00:00", "source_pdf_sha1": "aae8d0e445d8", "answer_pdf_sha1": "fb40082def78", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "426", "s": "2802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生行政學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "衛生行政"}'::jsonb, NULL),
  ('pukao-77f8735d-moex-00177', 'pukao-77f8735d', 'pukao-77f8735d-moex-110-85716566', 'sub-pukao-77f8735d-03', NULL, 'single_choice', '有關現行衛生福利部國民健康署癌症篩檢政策，下列敘述何者錯誤？', '["補助45-69歲婦女或40-44歲二等親內曾罹患乳癌婦女每2年一次乳房X光攝影篩檢", "30歲以上婦女建議每3年至少1次子宮頸抹片篩檢", "補助50-69歲民眾每2年1次糞便潛血篩檢", "補助30歲以上有嚼檳榔或吸菸者每2年1次口腔黏膜篩檢"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:05+00:00", "source_pdf_sha1": "aae8d0e445d8", "answer_pdf_sha1": "fb40082def78", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "426", "s": "2802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生行政學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "衛生行政"}'::jsonb, NULL),
  ('pukao-77f8735d-moex-00178', 'pukao-77f8735d', 'pukao-77f8735d-moex-110-85716566', 'sub-pukao-77f8735d-03', NULL, 'single_choice', '相較長照十年計劃1.0，下列何項是長期照護十年計畫2.0擴增的服務項目？', '["居家護理", "居家醫療", "居家及社區復健", "喘息服務"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:05+00:00", "source_pdf_sha1": "aae8d0e445d8", "answer_pdf_sha1": "fb40082def78", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "426", "s": "2802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生行政學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "衛生行政"}'::jsonb, NULL),
  ('pukao-77f8735d-moex-00179', 'pukao-77f8735d', 'pukao-77f8735d-moex-110-85716566', 'sub-pukao-77f8735d-03', NULL, 'single_choice', '有關預防接種受害救濟，下列敘述何者錯誤？', '["未經衛生福利部食品藥物管理署核准上市的疫苗，若發生不良反應，皆可提出申請", "依照傳染病防治法第5條和第30條規定，因預防接種而受害者，得請求救濟補償", "政府提供的公費疫苗接種在受害救濟保障範圍內", "預防接種受害基金來源主要由疫苗製造或輸入廠商應繳納一定金額作預防接種受害救濟基金"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:05+00:00", "source_pdf_sha1": "aae8d0e445d8", "answer_pdf_sha1": "fb40082def78", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "426", "s": "2802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生行政學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "衛生行政"}'::jsonb, NULL)
